#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

// Function f(x)
double f(double x) {
    return x * x * x - x - 2;
}

// Derivative f'(x)
double df(double x) {
    return 3 * x * x - 1;
}

// Regula Falsi Method with iterations
void regulaFalsi(double a, double b, int max_iter) {
    double c;

    cout << "\nRegula Falsi Method Iterations:\n";
    cout << "Iter\t a\t\t b\t\t c\t\t f(c)\n";

    for (int i = 1; i <= max_iter; i++) {
        c = (a * f(b) - b * f(a)) / (f(b) - f(a));

        cout << i << "\t "
             << fixed << setprecision(6)
             << a << "\t "
             << b << "\t "
             << c << "\t "
             << f(c) << endl;

        if (fabs(f(c)) < 0.0001)
            break;

        if (f(c) * f(a) < 0)
            b = c;
        else
            a = c;
    }

    cout << "Final Root (Regula Falsi): " << c << endl;
}

// Newton-Raphson with iterations
void newtonRaphson(double x0, int max_iter) {
    double x1;

    cout << "\nNewton-Raphson Method Iterations:\n";
    cout << "Iter\t x0\t\t x1\t\t f(x1)\n";

    for (int i = 1; i <= max_iter; i++) {
        x1 = x0 - f(x0) / df(x0);

        cout << i << "\t "
             << fixed << setprecision(6)
             << x0 << "\t "
             << x1 << "\t "
             << f(x1) << endl;

        if (fabs(f(x1)) < 0.0001)
            break;

        x0 = x1;
    }

    cout << "Final Root (Newton-Raphson): " << x1 << endl;
}

int main() {
    // Initial values
    double a = 1, b = 2;   // for Regula Falsi
    double x0 = 1.5;       // for Newton-Raphson
    int max_iter = 10;

    regulaFalsi(a, b, max_iter);
    newtonRaphson(x0, max_iter);

    return 0;
}
